/// Case-insensitive, allocation-free keyword lookup over a borrowed source word.
///
/// Length-bucketed (a word can only match a keyword of its own length); within a
/// bucket the lower-cased bytes are compared as a packed integer, so each
/// binary-search step is one register compare rather than a `memcmp` (the
/// byte-slice compare was ~9% of parse CPU on a release profile).
pub fn lookup_keyword(word: &str) -> Option<Keyword> {
    let bytes = word.as_bytes();
    match bytes.len() {
        1 => search(KEYWORDS_LEN_1, pack_u64(bytes)),
        2 => search(KEYWORDS_LEN_2, pack_u64(bytes)),
        3 => search(KEYWORDS_LEN_3, pack_u64(bytes)),
        4 => search(KEYWORDS_LEN_4, pack_u64(bytes)),
        5 => search(KEYWORDS_LEN_5, pack_u64(bytes)),
        6 => search(KEYWORDS_LEN_6, pack_u64(bytes)),
        7 => search(KEYWORDS_LEN_7, pack_u64(bytes)),
        8 => search(KEYWORDS_LEN_8, pack_u64(bytes)),
        9 => search(KEYWORDS_LEN_9, pack_u128(bytes)),
        10 => search(KEYWORDS_LEN_10, pack_u128(bytes)),
        11 => search(KEYWORDS_LEN_11, pack_u128(bytes)),
        12 => search(KEYWORDS_LEN_12, pack_u128(bytes)),
        13 => search(KEYWORDS_LEN_13, pack_u128(bytes)),
        14 => search(KEYWORDS_LEN_14, pack_u128(bytes)),
        15 => search(KEYWORDS_LEN_15, pack_u128(bytes)),
        16 => search(KEYWORDS_LEN_16, pack_u128(bytes)),
        17 => search_bytes(KEYWORDS_LEN_17, bytes),
        18 => search_bytes(KEYWORDS_LEN_18, bytes),
        19 => search_bytes(KEYWORDS_LEN_19, bytes),
        20 => search_bytes(KEYWORDS_LEN_20, bytes),
        21 => search_bytes(KEYWORDS_LEN_21, bytes),
        22 => search_bytes(KEYWORDS_LEN_22, bytes),
        23 => search_bytes(KEYWORDS_LEN_23, bytes),
        24 => search_bytes(KEYWORDS_LEN_24, bytes),
        25 => search_bytes(KEYWORDS_LEN_25, bytes),
        26 => search_bytes(KEYWORDS_LEN_26, bytes),
        27 => search_bytes(KEYWORDS_LEN_27, bytes),
        31 => search_bytes(KEYWORDS_LEN_31, bytes),
        32 => search_bytes(KEYWORDS_LEN_32, bytes),
        _ => None,
    }
}

/// Pack up to eight lower-cased bytes big-endian into a `u64` lookup key.
///
/// Big-endian so the integer order matches the byte-lexicographic order each
/// length bucket is sorted in, keeping the table a valid binary-search target.
/// Only `to_ascii_lowercase` folds case (A-Z only), so `_` and digits pass
/// through unchanged — the exact case-folding the byte-slice search used.
#[inline]
fn pack_u64(bytes: &[u8]) -> u64 {
    let mut key = 0u64;
    for &byte in bytes {
        key = (key << 8) | byte.to_ascii_lowercase() as u64;
    }
    key
}

/// Pack up to sixteen lower-cased bytes big-endian into a `u128` lookup key —
/// the `u64` key's wider sibling, for keywords of 9..=16 bytes.
#[inline]
fn pack_u128(bytes: &[u8]) -> u128 {
    let mut key = 0u128;
    for &byte in bytes {
        key = (key << 8) | byte.to_ascii_lowercase() as u128;
    }
    key
}

/// Binary-search a same-length bucket sorted ascending by its packed-integer
/// key (`u64` or `u128`).
#[inline]
fn search<Key: Copy + Ord>(table: &[(Key, Keyword)], key: Key) -> Option<Keyword> {
    table
        .binary_search_by_key(&key, |&(packed, _)| packed)
        .ok()
        .map(|index| table[index].1)
}

/// Longest keyword spelling; sizes the lower-casing buffer the byte-slice
/// fallback (keywords longer than sixteen bytes) lowers into.
const MAX_KEYWORD_LEN: usize = 32;

/// Byte-slice search for buckets too wide to pack into a `u128` (> 16 bytes):
/// lower-case into a fixed buffer, then binary-search the sorted byte tables.
fn search_bytes(table: &[(&[u8], Keyword)], word: &[u8]) -> Option<Keyword> {
    let mut lowered = [0u8; MAX_KEYWORD_LEN];
    for (slot, byte) in lowered.iter_mut().zip(word) {
        *slot = byte.to_ascii_lowercase();
    }
    let key = &lowered[..word.len()];
    table
        .binary_search_by(|(candidate, _)| (*candidate).cmp(key))
        .ok()
        .map(|index| table[index].1)
}

