/// MySQL 8.0 reserved words that are built-in function names — reserved as a column/type/bare-alias name but admissible as a function name, because MySQL parses `kw(...)` as a call (e.g. `LEFT`, `IF`, `MOD`). Mirrors the PostgreSQL `type_func_name` carve-out.
pub const MYSQL_TYPE_FUNC_NAME_KEYWORDS: super::KeywordSet = super::KeywordSet::from_keywords(&[
    Keyword::Char,
    Keyword::Convert,
    Keyword::Grouping,
    Keyword::If,
    Keyword::Insert,
    Keyword::Interval,
    Keyword::Left,
    Keyword::Mod,
    Keyword::Replace,
    Keyword::Right,
    Keyword::Values,
]);

/// MySQL 8.4 words reserved *only* as a function name — the inverse of `type_func_name`: admissible as a column/type/bare-alias name but rejected as a call head, because MySQL parses the bare word as an identifier yet syntax-rejects `kw(...)` (only `array`, engine-verified on 8.4.10). `dialect/keyword.rs` unions it into the MySQL function-name reject set alone.
pub const MYSQL_FUNCTION_ONLY_KEYWORDS: super::KeywordSet =
    super::KeywordSet::from_keywords(&[Keyword::Array]);
